from __future__ import annotations

from typing import Any

from starter_challenge.tracker import TrackerBase


def _extract_features(features: Any) -> list[dict]:
    """Extract the feature list from whatever format is passed.

    Tournament mode passes a scope dict: {"features": [...], ...}
    Direct calls pass a plain list of dicts.
    """
    if isinstance(features, dict):
        inner = features.get("features", [])
        if isinstance(inner, list):
            return inner
        return [features]
    if isinstance(features, list):
        return features
    return []


class SqftPriceTracker(TrackerBase):
    """Predicts price as living_area_sqft * $200/sqft."""

    def predict(self, features: list[dict[str, Any]]) -> dict:
        rows = _extract_features(features)
        if not rows:
            return {"predicted_price": 0.0}

        # Use the first feature row in the batch
        row = rows[0]
        living_area = float(row.get("living_area_sqft", 0.0))
        return {"predicted_price": living_area * 200}
